SELECT run_description 
FROM experiment_runs 
WHERE experiment_id = 1 AND run_date = '2023-01-01';

SELECT 
  (SELECT MAX(budget) FROM experiments) AS max_budget,
  (SELECT MAX(buffer_size) FROM experiment_runs) AS max_buffer_size;

SELECT COUNT(DISTINCT run_id) AS total_unique_runs, run_id
FROM experiment_runs
ORDER BY run_id;
